package store

import (
	"encoding/json"
	"path/filepath"
	"strings"
	"testing"
)

func TestOpenReadOnlyRejectsWrites(t *testing.T) {
	dbPath := filepath.Join(t.TempDir(), "data.db")
	writable, err := Open(dbPath)
	if err != nil {
		t.Fatalf("open writable: %v", err)
	}
	if _, _, err := writable.UpsertBatch("xml_response", []json.RawMessage{json.RawMessage(`{"id":"seed"}`)}); err != nil {
		t.Fatalf("seed writable store: %v", err)
	}
	if err := writable.Close(); err != nil {
		t.Fatalf("close writable: %v", err)
	}

	readOnly, err := OpenReadOnly(dbPath)
	if err != nil {
		t.Fatalf("open read-only: %v", err)
	}
	defer readOnly.Close()

	var total int
	if err := readOnly.DB().QueryRow(`SELECT COUNT(*) FROM resources`).Scan(&total); err != nil {
		t.Fatalf("read through read-only store: %v", err)
	}
	if total != 1 {
		t.Fatalf("resource count = %d, want 1", total)
	}

	_, err = readOnly.DB().Exec(`DELETE FROM resources WHERE id = 'seed'`)
	if err == nil {
		t.Fatal("DELETE through read-only store unexpectedly succeeded")
	}
	if !strings.Contains(strings.ToLower(err.Error()), "readonly") && !strings.Contains(strings.ToLower(err.Error()), "read-only") {
		t.Fatalf("DELETE error = %v, want read-only failure", err)
	}
}
